/*!
 * FileSaver.js
 * A saveAs() FileSaver implementation
 * @source http://purl.eligrey.com/github/FileSaver.js/blob/master/FileSaver.js
 * 
 * Improved version with modern JavaScript practices, better readability,
 * and comprehensive error handling.
 */

(function(global) {
    "use strict";

    // ============================================================================
    // Constants
    // ============================================================================
    
    const DEFAULT_TIMEOUT = 40000; // 40 seconds
    const OCTET_STREAM_MIME = 'application/octet-stream';
    const BOM_CHAR = '\uFEFF'; // Byte Order Mark for UTF-8
    
    // ============================================================================
    // Feature Detection
    // ============================================================================
    
    /**
     * Check if we're in a browser environment with required features
     */
    const isBrowserEnvironment = (
        typeof global !== 'undefined' &&
        typeof navigator !== 'undefined' &&
        !/MSIE [1-9]\./.test(navigator.userAgent) // No IE < 10
    );
    
    if (!isBrowserEnvironment) {
        // Not a supported browser environment, return no-op
        return;
    }
    
    const document = global.document;
    
    /**
     * Get the URL API (standard or vendor-prefixed)
     */
    const getURLAPI = () => global.URL || global.webkitURL || global;
    
    /**
     * Check if download attribute is supported
     */
    const supportsDownloadAttribute = (() => {
        const anchor = document.createElementNS('http://www.w3.org/1999/xhtml', 'a');
        return 'download' in anchor;
    })();
    
    /**
     * Check if we're in Safari with constructor issues
     */
    const isSafariWithConstructorIssue = /constructor/i.test(global.HTMLElement) || !!global.safari;
    
    /**
     * Check if we're in Chrome iOS
     */
    const isChromeIOS = /CriOS\/[\d]+/.test(navigator.userAgent);
    
    // ============================================================================
    // Utility Functions
    // ============================================================================
    
    /**
     * Dispatch a click event on an element
     * @param {HTMLElement} element - The element to click
     */
    const dispatchClickEvent = (element) => {
        const clickEvent = new MouseEvent('click');
        element.dispatchEvent(clickEvent);
    };
    
    /**
     * Schedule an error to be thrown asynchronously
     * @param {Error} error - The error to throw
     */
    const scheduleErrorThrow = (error) => {
        (global.setImmediate || global.setTimeout)(() => {
            throw error;
        }, 0);
    };
    
    /**
     * Schedule a cleanup function to run after a timeout
     * @param {Function} cleanupFn - The cleanup function to run
     * @param {number} timeout - Timeout in milliseconds
     */
    const scheduleCleanup = (cleanupFn, timeout = DEFAULT_TIMEOUT) => {
        setTimeout(cleanupFn, timeout);
    };
    
    /**
     * Revoke an object URL or remove a blob
     * @param {string|Blob} object - Object URL string or Blob
     */
    const revokeObject = (object) => {
        const cleanup = () => {
            if (typeof object === 'string') {
                getURLAPI().revokeObjectURL(object);
            } else if (object && typeof object.remove === 'function') {
                object.remove();
            }
        };
        
        scheduleCleanup(cleanup);
    };
    
    /**
     * Trigger callbacks for an event
     * @param {Object} target - The target object with callbacks
     * @param {string|string[]} events - Event name(s) to trigger
     * @param {Event} [event] - Optional event object
     */
    const triggerCallbacks = (target, events, event) => {
        const eventList = Array.isArray(events) ? events : [events];
        
        for (const eventName of eventList) {
            const callback = target['on' + eventName];
            if (typeof callback === 'function') {
                try {
                    callback.call(target, event || target);
                } catch (error) {
                    scheduleErrorThrow(error);
                }
            }
        }
    };
    
    /**
     * Add UTF-8 BOM to text blobs if needed
     * @param {Blob} blob - The blob to process
     * @returns {Blob} Processed blob with BOM if applicable
     */
    const addUtf8BomIfNeeded = (blob) => {
        const isTextWithUtf8Charset = /^\s*(?:text\/\S*|application\/xml|\S*\/\S*\+xml)\s*;.*charset\s*=\s*utf-8/i.test(blob.type);
        
        if (isTextWithUtf8Charset) {
            return new Blob([BOM_CHAR, blob], { type: blob.type });
        }
        
        return blob;
    };
    
    // ============================================================================
    // Main SaveAs Function
    // ============================================================================
    
    /**
     * Save a blob or file with the given name
     * @param {Blob} blob - The blob to save
     * @param {string} [filename] - The filename to use
     * @param {Object} [options] - Additional options
     * @returns {SaveAsObject} SaveAs instance
     */
    const saveAs = (blob, filename, options = {}) => {
        // Handle optional filename
        if (!filename) {
            filename = blob.name || 'download';
        }
        
        // Add BOM for UTF-8 text files if not disabled
        if (!options.skipBom) {
            blob = addUtf8BomIfNeeded(blob);
        }
        
        // Use MS-specific save API if available
        if (typeof navigator !== 'undefined' && navigator.msSaveOrOpenBlob) {
            return navigator.msSaveOrOpenBlob(blob, filename);
        }
        
        return new SaveAsObject(blob, filename, options);
    };
    
    // ============================================================================
    // SaveAsObject Class
    // ============================================================================
    
    /**
     * SaveAsObject constructor
     * @param {Blob} blob - The blob to save
     * @param {string} filename - The filename to use
     * @param {Object} options - Additional options
     */
    function SaveAsObject(blob, filename, options = {}) {
        this.readyState = this.INIT;
        this.blob = blob;
        this.filename = filename;
        this.options = options;
        this._objectURL = null;
        
        this.error = null;
        this.onwritestart = null;
        this.onprogress = null;
        this.onwrite = null;
        this.onabort = null;
        this.onerror = null;
        this.onwriteend = null;
        
        this._initSave();
    }
    
    // Static properties
    SaveAsObject.prototype.INIT = 0;
    SaveAsObject.prototype.WRITING = 1;
    SaveAsObject.prototype.DONE = 2;
    
    /**
     * Initialize the save operation
     * @private
     */
    SaveAsObject.prototype._initSave = function() {
        triggerCallbacks(this, 'writestart');
        
        const blobType = this.blob.type;
        const isOctetStream = blobType === OCTET_STREAM_MIME;
        
        // Chrome iOS special handling
        if (isChromeIOS || (isOctetStream && isSafariWithConstructorIssue)) {
            this._saveViaFileReader();
            return;
        }
        
        // Download attribute supported
        if (supportsDownloadAttribute) {
            this._saveViaDownloadAttribute();
            return;
        }
        
        // Fallback to opening in new window/tab
        this._saveViaWindowOpen();
    };
    
    /**
     * Save via download attribute (modern browsers)
     * @private
     */
    SaveAsObject.prototype._saveViaDownloadAttribute = function() {
        this._objectURL = getURLAPI().createObjectURL(this.blob);
        
        setTimeout(() => {
            const anchor = document.createElementNS('http://www.w3.org/1999/xhtml', 'a');
            anchor.href = this._objectURL;
            anchor.download = this.filename;
            
            dispatchClickEvent(anchor);
            triggerCallbacks(this, 'write writeend');
            
            revokeObject(this._objectURL);
            this.readyState = this.DONE;
        }, 0);
    };
    
    /**
     * Save via FileReader (for Chrome iOS and Safari)
     * @private
     */
    SaveAsObject.prototype._saveViaFileReader = function() {
        this.readyState = this.INIT;
        
        const reader = new FileReader();
        
        reader.onloadend = () => {
            let dataURL = reader.result;
            
            // Fix for Chrome iOS
            if (isChromeIOS) {
                dataURL = dataURL.replace(/^data:[^;]*;/, 'data:attachment/file;');
            }
            
            const newWindow = global.open(dataURL, '_blank');
            if (!newWindow) {
                global.location.href = dataURL;
            }
            
            dataURL = undefined; // Help GC
            this.readyState = this.DONE;
            triggerCallbacks(this, 'write writeend');
        };
        
        reader.readAsDataURL(this.blob);
    };
    
    /**
     * Save via window.open (fallback)
     * @private
     */
    SaveAsObject.prototype._saveViaWindowOpen = function() {
        if (!this._objectURL) {
            this._objectURL = getURLAPI().createObjectURL(this.blob);
        }
        
        const blobType = this.blob.type;
        const isOctetStream = blobType === OCTET_STREAM_MIME;
        
        if (isOctetStream) {
            global.location.href = this._objectURL;
        } else {
            const newWindow = global.open(this._objectURL, '_blank');
            if (!newWindow) {
                global.location.href = this._objectURL;
            }
        }
        
        this.readyState = this.DONE;
        triggerCallbacks(this, 'write writeend');
        revokeObject(this._objectURL);
    };
    
    /**
     * Abort the save operation (not implemented)
     */
    SaveAsObject.prototype.abort = function() {
        // Abort not implemented
    };
    
    // ============================================================================
    // Export
    // ============================================================================
    
    // Determine the global object
    const globalObject = (
        typeof self !== 'undefined' && self ||
        typeof window !== 'undefined' && window ||
        typeof global !== 'undefined' && global ||
        this
    );
    
    // Export saveAs to the global object
    globalObject.saveAs = saveAs;
    
    // Module exports
    if (typeof module !== 'undefined' && module.exports) {
        module.exports.saveAs = saveAs;
    } else if (typeof define !== 'undefined' && define !== null && define.amd !== null) {
        define('FileSaver.js', [], () => saveAs);
    }
    
})(typeof self !== 'undefined' ? self : typeof window !== 'undefined' ? window : this);
